module sync_reset_register(clk, reset, d, q);

    input  clk;  
    input  reset;  
    input  [7:0] d;  
    output  [7:0] q;  
  wire _tap_clk = clk & {1{1'b1}};

    reg    [7:0] q; 
    initial q = 0;

    always @(posedge clk)
          begin
            if (reset) 
                q <= 0;
            else
                q <= d;
          end  

endmodule
